3367 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3368                                                FPClassTest DemandedMask,
3369                                                KnownFPClass &Known,
3370                                                unsigned Depth) {
3371   Use &U = I->getOperandUse(OpNo);
3372   Value *V = U.get();
3373   Type *VTy = V->getType();
3374 
3375   if (DemandedMask == fcNone) {
3376     if (isa<UndefValue>(V))
3377       return false;
3378     replaceUse(U, PoisonValue::get(VTy));
3379     return true;
3380   }
3381 
3382   // Handle constant
3383   Instruction *VInst = dyn_cast<Instruction>(V);
3384   if (!VInst) {
3385     // Handle constants and arguments
3386     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3387     Known.knownNot(~DemandedMask);
3388 
3389     if (Known.KnownFPClasses == fcNone) {
3390       if (isa<UndefValue>(V))
3391         return false;
3392       replaceUse(U, PoisonValue::get(VTy));
3393       return true;
3394     }
3395 
3396     // Do not try to replace values which are already constants (unless we are
3397     // folding to poison). Doing so could promote poison elements to non-poison
3398     // constants.
3399     if (isa<Constant>(V))
3400       return false;
3401 
3402     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3403     if (!FoldedToConst || FoldedToConst == V)
3404       return false;
3405 
3406     replaceUse(U, FoldedToConst);
3407     return true;
3408   }
3409 
3410   if (Depth == MaxAnalysisRecursionDepth)
3411     return false;
3412 
3413   Value *NewVal;
3414 
3415   if (VInst->hasOneUse()) {
3416     // If the instruction has one use, we can directly simplify it.
3417     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3418   } else {
3419     // If there are multiple uses of this instruction, then we can simplify
3420     // VInst to some other value, but not modify the instruction.
3421     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3422                                                 Depth);
3423   }
3424 
3425   if (!NewVal)
3426     return false;
3427   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3428     salvageDebugInfo(*OpInst);
3429 
3430   replaceUse(U, NewVal);
3431   return true;
3432 }
